  9→} from "react-resizable-panels";
 10→import { PanelEditHeader } from "./panel-edit-header";
 11→import { PanelEditPreview } from "./panel-edit-preview";
 12→import { PanelEditSidebar } from "./panel-edit-sidebar";
 13→import { PanelEditSqlEditor } from "./panel-edit-sql-editor";
 14→import { usePanelEditState } from "./use-panel-edit-state";
 15→
 16→interface PanelEditViewProps {
 17→  editingPanel?: PanelDescriptor | null;
 18→  onSave: (panel: PanelDescriptor) => void;
 19→  onDiscard: () => void;
 20→}
 21→
 22→function PanelEditViewComponent({
 23→  editingPanel,
 24→  onSave,
 25→  onDiscard,
 26→}: PanelEditViewProps) {
 27→  const state = usePanelEditState(editingPanel);
 28→
 29→  const handleApply = useCallback(() => {
 30→    const descriptor = state.buildDescriptor();
 31→    if (descriptor) {
 32→      onSave(descriptor);
 33→    }
 34→  }, [state.buildDescriptor, onSave]);
 35→
 36→  return (
 37→    <div className="fixed inset-0 z-50 bg-background flex flex-col">
 38→      {/* Header */}
 39→      <PanelEditHeader
 40→        title={state.title}
 41→        onTitleChange={state.setTitle}
 42→        onRunQuery={state.runQuery}
 43→        onApply={handleApply}
 44→        onDiscard={onDiscard}
 45→        isDirty={state.isDirty}
 46→        isValid={state.isValid}
 47→      />
 48→
 49→      {/* Body: resizable panels */}
 50→      <div className="flex-1 min-h-0">
 51→        <PanelGroup direction="horizontal">
 52→          {/* Left: Preview + SQL editor (vertical split) */}
 53→          <Panel defaultSize={65} minSize={35}>
 54→            <PanelGroup direction="vertical">
 55→              {/* Top: Preview */}
 56→              <Panel defaultSize={55} minSize={15}>
 57→                <PanelEditPreview
 58→                  descriptor={state.previewDescriptor}
 59→                  previewKey={state.previewKey}
 60→                />
 61→              </Panel>
 62→
 63→              <PanelResizeHandle className="h-1 bg-border hover:bg-primary/20 transition-colors data-[resize-handle-active]:bg-primary/30" />
 64→
 65→              {/* Bottom: SQL editor */}
 66→              <Panel defaultSize={45} minSize={15}>
 67→                <PanelEditSqlEditor
 68→                  initialSql={state.sql}
 69→                  onSqlChange={state.setSql}
 70→                  onRunQuery={state.runQuery}
 71→                />
 72→              </Panel>
 73→            </PanelGroup>
 74→          </Panel>
 75→
 76→          <PanelResizeHandle className="w-1 bg-border hover:bg-primary/20 transition-colors data-[resize-handle-active]:bg-primary/30" />
 77→
 78→          {/* Right: Configuration sidebar */}
 79→          <Panel defaultSize={35} minSize={20} maxSize={50}>
 80→            <PanelEditSidebar
 81→              chartType={state.chartType}
 82→              onChartTypeChange={state.setChartType}
 83→              gridW={state.gridW}
 84→              gridH={state.gridH}
 85→              onGridSizeChange={state.setGridSize}
 86→              statOptions={state.statOptions}
 87→              onStatOptionsChange={state.updateStatOptions}
 88→              timeseriesOptions={state.timeseriesOptions}
 89→              onTimeseriesOptionsChange={state.updateTimeseriesOptions}
 90→              pieOptions={state.pieOptions}
 91→              onPieOptionsChange={state.updatePieOptions}
 92→              gaugeOptions={state.gaugeOptions}
 93→              onGaugeOptionsChange={state.updateGaugeOptions}
 94→              tableOptions={state.tableOptions}
 95→              onTableOptionsChange={state.updateTableOptions}
 96→              isNewPanel={!editingPanel}
 97→              onApplyTemplate={state.applyTemplate}
 98→            />
 99→          </Panel>
100→        </PanelGroup>
101→      </div>
102→    </div>
103→  );
104→}
