  return (
    <div className="flex flex-col h-full">
      {/* Sidebar header */}
      <div className="flex items-center px-3 py-1.5 border-b bg-muted/30 shrink-0">
        <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
          Panel Options
        </span>
      </div>

      <ScrollArea className="flex-1">
        <div className="divide-y">
          {/* Templates section (for new panels) */}
          {isNewPanel && (
            <Section title="Templates" defaultOpen={false}>
              <div className="grid grid-cols-1 gap-1.5">
                {WIDGET_TEMPLATES.map((t) => (
                  <button
                    key={t.name}
                    type="button"
                    className="text-left p-2 rounded-md border hover:bg-muted/50 transition-colors"
                    onClick={() => onApplyTemplate(t)}
                  >
                    <div className="text-xs font-medium">{t.name}</div>
                    <div className="text-[10px] text-muted-foreground">
                      {t.description}
