          {chartType === "gauge" && (
            <GaugeOptionsSection
              options={gaugeOptions}
              onChange={onGaugeOptionsChange}
            />
          )}
          {chartType === "table" && (
            <TableOptionsSection
              options={tableOptions}
              onChange={onTableOptionsChange}
            />
