                desc="Time bucket size in seconds"
              />
              <VarRow
                name="{seconds:UInt32}"
                desc="Total time range in seconds"
              />
            </div>
          </Section>
        </div>
      </ScrollArea>
    </div>
  );
}

// --- Variable Reference Row ---
